// ========== GE-SPECIFIC FAQ SUB-COMPONENT ==========
function GECategoryFAQ() {
  const [openFAQ, setOpenFAQ] = useState(-1);
  const faqs = [
    { q: "Do you stock GE parts that are officially end-of-life?", a: "Yes — and it's one of our specialisations. The Mark V platform hit end-of-life at GE around 2014, but we still hold active inventory of 48 SKUs across our warehouse network. We track obsolescence status per SKU and flag parts where remaining stock is limited or where cross-reference to a newer generation is required. Our Mark V engineers can advise on fit-for-purpose alternatives when a specific legacy module is genuinely unavailable." },
    { q: "Can you verify that a unit is genuine GE rather than a clone?", a: "Every GE unit in our catalogue is authenticated against manufacturer records before intake, with serial-number cross-checks and visual inspection under magnification. Counterfeit Mark VI/VIe modules do circulate in the secondary market, and our intake process is specifically designed to reject them. If your site has experienced a suspicious failure on a unit sourced elsewhere, we can review photographs and confirm whether it is genuine or a clone." },
    { q: "What's the upgrade path from Mark V to Mark VIe?", a: "Mark V to Mark VIe is not a drop-in upgrade — it is a full controller replacement with new I/O mapping, new HMI integration, and typically new cabling to the field. We do not perform the upgrade itself (that is a systems-integrator scope), but we supply the Mark V modules to keep the existing platform running until a planned upgrade window, and we supply the Mark VIe target hardware when the project begins. Our migration guide document (downloadable above) walks through the planning considerations." },
    { q: "Do you offer repair services, or only replacement?", a: "We are primarily a replacement-parts supplier, not a repair house. However, for a subset of Mark VI/VIe modules we offer board-level repair through a partner network, with turnaround typically 3–6 weeks and a 12-month warranty on repaired units. Repair is usually only cost-effective for higher-value controllers; for standard I/O cards, replacement from our stock is faster and more economic." },
    { q: "How do I read a GE Mark VI part number?", a: "A typical Mark VI part number like IS200EDISG1AAA breaks down as: IS200 = Mark VI series identifier, EDIS = functional acronym (Exciter Distribution), G1 = revision level, AAA = variant/firmware suffix. The last three characters matter most for compatibility — a unit can be labelled IS200EDISG1A or IS200EDISG1AAA and they are not always interchangeable. When in doubt, send us the label photo and we will confirm the exact match." }
  ];

  return (
    <div className="divide-y divide-[#E5E1D8] border-t border-b border-[#E5E1D8]">
      {faqs.map((item, i) => (
        <button key={i} onClick={() => setOpenFAQ(openFAQ === i ? -1 : i)} className="w-full py-6 text-left flex items-start justify-between gap-6 group">
          <div className="flex-1">
            <div className="flex items-start gap-4">
              <span className="font-mono-tech text-xs text-[#8B8680] tnum pt-1.5">{String(i+1).padStart(2,'0')}</span>
              <div className="flex-1">
                <div className="font-display text-xl font-semibold group-hover:text-[#E85D2F] transition">{item.q}</div>
                {openFAQ === i && <div className="mt-4 text-[#0A1628]/70 leading-relaxed pr-8">{item.a}</div>}
              </div>
            </div>
          </div>
          <span className={`mt-1 border w-9 h-9 flex items-center justify-center transition flex-shrink-0 ${openFAQ === i ? "bg-[#E85D2F] text-white border-[#E85D2F]" : "border-[#E5E1D8] text-[#8B8680] group-hover:border-[#E85D2F] group-hover:text-[#E85D2F]"}`}>
            {openFAQ === i ? <X className="w-4 h-4"/> : <ChevronRight className="w-4 h-4"/>}
          </span>
        </button>
      ))}
    </div>
  );
}
